class TimestampMixin(models.Model):
    """Adds created_at and updated_at fields."""

    created_at = models.DateTimeField(auto_now_add=True, db_index=True)
    updated_at = models.DateTimeField(auto_now=True)

    class Meta:
        abstract = True

class ArticleQuerySet(models.QuerySet):
    """Custom queryset for articles."""

    def published(self):
        return self.filter(status='published')

    def draft(self):
        return self.filter(status='draft')

    def by_author(self, author):
        return self.filter(author=author)

    def recent(self, days=30):
        from django.utils import timezone
        from datetime import timedelta
        cutoff = timezone.now() - timedelta(days=days)
        return self.filter(created_at__gte=cutoff)


class ArticleManager(models.Manager):
    """Manager using ArticleQuerySet."""

    def get_queryset(self):
        return ArticleQuerySet(self.model, using=self._db)

    def published(self):
        return self.get_queryset().published()

    def recent(self, days=30):
        return self.get_queryset().recent(days)


# Alternative: Manager from QuerySet (DRY)
ArticleManager = ArticleQuerySet.as_manager()

from django.db import models
from django.utils import timezone


class SoftDeleteManager(models.Manager):
    """Excludes soft-deleted records by default."""

    def get_queryset(self):
        return super().get_queryset().filter(deleted_at__isnull=True)


class AllObjectsManager(models.Manager):
    """Includes all records (deleted and active)."""
    pass


class SoftDeleteMixin(models.Model):
    """Adds soft delete capability."""

    deleted_at = models.DateTimeField(null=True, blank=True, db_index=True)

    objects = SoftDeleteManager()
    all_objects = AllObjectsManager()

    class Meta:
        abstract = True

    def delete(self, using=None, keep_parents=False):
        """Soft delete instead of hard delete."""
        self.deleted_at = timezone.now()
        self.save(update_fields=['deleted_at', 'updated_at'])

    def hard_delete(self):
        """Permanently delete from database."""
        super().delete()

    def restore(self):
        """Restore soft-deleted record."""
        self.deleted_at = None
        self.save(update_fields=['deleted_at', 'updated_at'])

    @property
    def is_deleted(self) -> bool:
        return self.deleted_at is not None

from django.db import models
from django.conf import settings


class TenantManager(models.Manager):
    """Manager that filters by current tenant."""

    def get_queryset(self):
        from .middleware import get_current_tenant
        tenant = get_current_tenant()
        if tenant:
            return super().get_queryset().filter(tenant=tenant)
        return super().get_queryset()


class TenantAwareModel(models.Model):
    """Abstract base for tenant-scoped models."""

    tenant = models.ForeignKey(
        'tenants.Tenant',
        on_delete=models.CASCADE,
        related_name='%(class)s_set',
    )

    objects = TenantManager()
    unscoped = models.Manager()  # Access all tenants (admin only)

    class Meta:
        abstract = True

    def save(self, *args, **kwargs):
        if not self.tenant_id:
            from .middleware import get_current_tenant
            self.tenant = get_current_tenant()
        super().save(*args, **kwargs)

from django.db import models
class Order(models.Model): """Ownership relationship.""" user = models.ForeignKey(User, on_delete=models.PROTECT) # Don't lose order history
class OrderItem(models.Model): """Composition: items belong to order.""" order = models.ForeignKey(Order, on_delete=models.CASCADE) # Items meaningless without order
class Task(models.Model): """Assignment: task survives user deletion.""" assigned_to = models.ForeignKey( User, on_delete=models.SET_NULL, # Preserve task, clear assignment null=True, blank=True )
class Comment(models.Model): """Attribution: preserve content, clear author.""" author = models.ForeignKey( User, on_delete=models.SET_NULL, null=True, blank=True )
